const webhookData = $('Webhook Trigger').first().json;
const body = webhookData.body || webhookData;
const { projectId, requiredSkills } = body;

const agentResponse = $('Fetch Agents').first().json;
const agents = Array.isArray(agentResponse) ? agentResponse : (agentResponse.data || agentResponse.agents || []);

const skillList = Array.isArray(requiredSkills) ? requiredSkills : [];

const agentSkillMap = {};
agents.forEach(agent => {
  const name = agent.name || agent.id;
  const skills = agent.skills || agent.capabilities || [];
  agentSkillMap[name] = {
    skills: Array.isArray(skills) ? skills.map(s => typeof s === 'string' ? s : s.name || s.id) : [],
    tier: agent.tier || 'T3',
    status: agent.status || 'available',
    adapterType: agent.adapterType || 'unknown'
  };
});

const coverage = skillList.map(requiredSkill => {
  const normalizedSkill = requiredSkill.toLowerCase().trim();
  const matchingAgents = [];

  Object.entries(agentSkillMap).forEach(([agentName, agentInfo]) => {
    const hasSkill = agentInfo.skills.some(s => {
      const normalizedAgentSkill = s.toLowerCase().trim();
      return normalizedAgentSkill === normalizedSkill ||
             normalizedAgentSkill.includes(normalizedSkill) ||
             normalizedSkill.includes(normalizedAgentSkill);
    });

    if (hasSkill) {
      matchingAgents.push({
        agent: agentName,
        tier: agentInfo.tier,
        status: agentInfo.status,
        adapterType: agentInfo.adapterType
      });
    }
  });

  return {
    skill: requiredSkill,
    covered: matchingAgents.length > 0,
    agentCount: matchingAgents.length,
    agents: matchingAgents,
    redundancy: matchingAgents.length > 1 ? 'adequate' : matchingAgents.length === 1 ? 'single-point' : 'none'
  };
});

const coveredCount = coverage.filter(c => c.covered).length;
const coveragePercent = skillList.length > 0
  ? Math.round((coveredCount / skillList.length) * 100)
  : 100;

return [{
  json: {
    projectId,
    requiredSkills: skillList,
    totalAgents: agents.length,
    coverage,
    coveragePercent
  }
}];

const data = $json;
const { projectId, coverage, coveragePercent } = data;

const gaps = coverage
  .filter(c => !c.covered)
  .map(c => ({
    skill: c.skill,
    severity: 'high',
    impact: 'No agent available to handle ' + c.skill + ' tasks'
  }));

const singlePoints = coverage
  .filter(c => c.redundancy === 'single-point')
  .map(c => ({
    skill: c.skill,
    agent: c.agents[0].agent,
    severity: 'medium',
    impact: 'Only ' + c.agents[0].agent + ' covers ' + c.skill + ' — bus factor of 1'
  }));

const recommendations = [];

gaps.forEach(gap => {
  recommendations.push({
    type: 'create-specialist',
    priority: 'high',
    skill: gap.skill,
    action: 'Create a new T3 ephemeral specialist with ' + gap.skill + ' capability via Aria',
    rationale: 'No existing agent covers this required skill'
  });
});

singlePoints.forEach(sp => {
  recommendations.push({
    type: 'add-redundancy',
    priority: 'medium',
    skill: sp.skill,
    action: 'Train or create a second agent with ' + sp.skill + ' capability',
    rationale: 'Single point of failure — if ' + sp.agent + ' is unavailable, ' + sp.skill + ' tasks will block'
  });
});

if (coveragePercent < 80) {
  recommendations.push({
    type: 'coverage-alert',
    priority: 'critical',
    action: 'Overall coverage is ' + coveragePercent + '% — urgent specialist recruitment needed',
    rationale: 'Project may stall due to insufficient skill coverage'
  });
}

return [{
  json: {
    projectId,
    coverage: data.coverage,
    gaps,
    singlePoints,
    recommendations,
    summary: {
      totalRequired: data.requiredSkills.length,
      covered: data.coverage.filter(c => c.covered).length,
      uncovered: gaps.length,
      singlePointRisks: singlePoints.length,
      coveragePercent,
      totalAgents: data.totalAgents,
      recommendationCount: recommendations.length
    },
    completedAt: new Date().toISOString()
  }
}];
